%% P4_Exp01_fixed_scale_LFP_optimization.m
% Purpose:
% This script implements the fixed-scale LFP recertification optimization.
%
% It combines SOH-dependent action-value functions, the k-dependent
% residual-error model generated by Part3, threshold-based action allocation,
% and decision-loss accounting to identify the optimal target-domain
% labelling investment k and the corresponding SOH thresholds T1 and T2
% under a fixed deployment scale.

clear; clc; close all;

%% 1) Configuration
cfg = struct();

% Use the current script folder as the Part4 root folder.
script_dir = fileparts(mfilename('fullpath'));

if isempty(script_dir)
    script_dir = pwd;
end

% Use the parent folder as the project root.
project_root = fileparts(script_dir);

% Part4 folders.
cfg.input_dir = fullfile(script_dir, 'Input');
cfg.output_dir = fullfile(script_dir, 'Output');
cfg.results_dir = fullfile(cfg.output_dir, 'Results');

cfg.figure_root = fullfile(script_dir, 'Figures');
cfg.main_fig_dir = fullfile(cfg.figure_root, 'Main');

cfg.function_dir = fullfile(script_dir, 'Function');

% Input files.
cfg.lfp_soh_mat = fullfile(cfg.input_dir, 'LFP_SOH_Table.mat');

% Primary Part3 residual-error model path using the new naming convention.
cfg.error_model_mat_primary = fullfile(project_root, ...
    'Part3_Prediction error extrapolation', ...
    'Output', ...
    'Results', ...
    'P3_Exp03_ResidualExtrapolation_Model.mat');

% Legacy fallback path for the old Part3 Main03 output.
cfg.error_model_mat_legacy = fullfile(project_root, ...
    'Part3_Prediction error extrapolation', ...
    'Output', ...
    'Result03_ResidualExtrapolation_Model.mat');

if exist(cfg.error_model_mat_primary, 'file')
    cfg.error_model_mat = cfg.error_model_mat_primary;
elseif exist(cfg.error_model_mat_legacy, 'file')
    cfg.error_model_mat = cfg.error_model_mat_legacy;
else
    error('Part3 residual-error model file not found. Checked:\n%s\n%s', ...
        cfg.error_model_mat_primary, cfg.error_model_mat_legacy);
end

% Output files generated by Part4 Exp01.
cfg.workspace_mat = fullfile(cfg.results_dir, ...
    'P4_Exp01_FixedScale_LFP_Workspace.mat');

cfg.result_mat = fullfile(cfg.results_dir, ...
    'P4_Exp01_FixedScale_LFP_Results.mat');

cfg.summary_csv = fullfile(cfg.results_dir, ...
    'P4_Exp01_FixedScale_LFP_Summary.csv');

% Figure subfolders and figure-output paths for Main Fig. 2 and Main Fig. 3.
cfg.landscape_dir = fullfile(cfg.main_fig_dir, ...
    'MainFig02c_threshold_cost_landscapes');

cfg.confusion_dir = fullfile(cfg.main_fig_dir, ...
    'MainFig02d_confusion_matrices');

cfg.loss_matrix_dir = fullfile(cfg.main_fig_dir, ...
    'MainFig02e_value_loss_matrices');

cfg.fig_cost_breakdown = fullfile(cfg.main_fig_dir, ...
    'MainFig02b_fixed_scale_LFP_cost_decomposition.fig');
cfg.png_cost_breakdown = fullfile(cfg.main_fig_dir, ...
    'MainFig02b_fixed_scale_LFP_cost_decomposition.png');

cfg.fig_net_value = fullfile(cfg.main_fig_dir, ...
    'MainFig03a_LFP_net_value_curves.fig');
cfg.png_net_value = fullfile(cfg.main_fig_dir, ...
    'MainFig03a_LFP_net_value_curves.png');

cfg.fig_A3_breakdown = fullfile(cfg.main_fig_dir, ...
    'MainFig03b_LFP_recycling_breakdown.fig');
cfg.png_A3_breakdown = fullfile(cfg.main_fig_dir, ...
    'MainFig03b_LFP_recycling_breakdown.png');

% Simulation settings.
cfg.N_sim = 100000;
cfg.random_seed = 42;
cfg.png_resolution = 600;

% Create required folders.
folder_list = { ...
    cfg.input_dir, ...
    cfg.output_dir, ...
    cfg.results_dir, ...
    cfg.figure_root, ...
    cfg.main_fig_dir, ...
    cfg.function_dir, ...
    cfg.landscape_dir, ...
    cfg.confusion_dir, ...
    cfg.loss_matrix_dir};

for ii = 1:numel(folder_list)
    if ~exist(folder_list{ii}, 'dir')
        mkdir(folder_list{ii});
    end
end

addpath(cfg.function_dir);

if exist('local_build_noise_by_k', 'file') ~= 2
    error('Function local_build_noise_by_k.m was not found in: %s', cfg.function_dir);
end

fprintf('================ Part4 Exp01 fixed-scale LFP optimization ================\n');
fprintf('LFP SOH input file:      %s\n', cfg.lfp_soh_mat);
fprintf('Part3 error model file:  %s\n', cfg.error_model_mat);
fprintf('Output result file:      %s\n', cfg.result_mat);
fprintf('Output workspace file:   %s\n', cfg.workspace_mat);
fprintf('Summary CSV file:        %s\n', cfg.summary_csv);
fprintf('Main figure folder:      %s\n', cfg.main_fig_dir);
fprintf('Random seed:             %d\n', cfg.random_seed);

%% 2) Load LFP SOH trajectory data
if ~exist(cfg.lfp_soh_mat, 'file')
    error('LFP SOH data file not found: %s', cfg.lfp_soh_mat);
end

SOH_file = load(cfg.lfp_soh_mat);
SOH_data = local_extract_soh_from_mat(SOH_file, cfg.lfp_soh_mat);

fprintf('LFP SOH trajectory loaded. Number of SOH points = %d\n', numel(SOH_data));
fprintf('LFP SOH range: %.4f - %.4f\n', min(SOH_data), max(SOH_data));

%% 3) Basic physical and economic parameters

Q_pack = 25.3;
r = 0.05;
beta_refurbish = 0.09;

% Shenzhen tier-2 residential peak-valley electricity prices, RMB/kWh
ExchangeRate_RMB_USD = 7.04;
p_high_RMB = 1.1621;
p_low_RMB  = 0.2986;

% Convert electricity prices to USD/kWh
p_high = p_high_RMB / ExchangeRate_RMB_USD;   % 0.1651
p_low  = p_low_RMB  / ExchangeRate_RMB_USD;   % 0.0424

c_pack = 300;                 c_train = 100;                Fixed_Scale_N = 2500;
% SOH testing cost      model training cost        fixed deployment scale


Eta_1 = 40;          Eta_2 = 40;
% G1 gray-zone tolerance between recycling and refurbishment
% G2 gray-zone tolerance between reuse and refurbishment

% Refurbishment cost parameters
C0 = 92;      % baseline labor, disassembly, and inspection cost
C1 = 65;      % material replacement and deep-repair cost coefficient
gamma = 3;    % nonlinear degradation exponent for refurbishment difficulty

Lambda_R = 15;    Lambda_H = 12;
% Lambda_R scales the risk penalty for over-optimistic pathway assignment.
% Lambda_H is the fixed mismatch-handling and rework cost incurred for an
% economically consequential pathway mismatch. It does not represent an
% ex-ante review that corrects the pathway before opportunity loss occurs.
%
% Legacy alias retained for compatibility with older downstream scripts.
Lambda_A = Lambda_H;


% 1.1 Hydrometallurgical recycling economics and physicochemical parameters

M_pack = 173.25;                Exchange_Rate = 1;
% pack mass (kg)               exchange-rate multiplier

% - 1. Baseline physicochemical parameters per kg battery pack -
PosAcMass = 0.223;           PosCCMass = 0.060;          NegAcMass = 0.1235;        NegCCMass = 0.08;
% positive active material   positive current collector    negative active material       negative current collector

M_LiFePO4 = 157.76;     M_Li2CO3_half = 73.88;    M_FePO4 = 150.82;    M_H2SO4 = 98;    M_H2O2 = 34;    M_Na2CO3 = 106;
% Molar-mass parameters

% - 1.5 Recovery-efficiency parameters for the hydrometallurgical process -
Rec_Rate_Chem = 0.98;    Rec_Rate_Graphite = 0.95;        Rec_Rate_Al = 0.93;      Rec_Rate_Cu = 0.93;
% reaction conversion rate for Li2CO3 and FePO4   graphite   aluminum collector   copper collector

% - 2. Market prices of recovered products, USD/kg -
P_Li2CO3   = 27.20;     P_FePO4    = 1.91;     P_Graphite = 3.84;    P_Al = 3.42;     P_Cu = 14.79;
% Li2CO3 price   FePO4 price   graphite price   aluminum price   copper price

% - 3. Product yields independent of SOH, kg/kg battery -
Base_Y_FePO4    = (PosAcMass / M_LiFePO4) * M_FePO4 * Rec_Rate_Chem;
Base_Y_Graphite = NegAcMass * Rec_Rate_Graphite;
Base_Y_Al = PosCCMass * Rec_Rate_Al;      Base_Y_Cu  = NegCCMass * Rec_Rate_Cu;

% - 4. Feedstock and reagent prices for hydrometallurgical recycling -
C_Degraded = 2.05;     P_H2SO4    = 0.264;      P_H2O2     = 0.130;      P_Na2CO3   =  0.172;
% retired LFP feedstock cost   H2SO4 price   H2O2 price   Na2CO3 price

% - 5. LFP hydrometallurgical recycling fixed operating cost -
P_elec_recycle = 0.111;   % USD/kWh

C_Electricity_hydro = 500 * P_elec_recycle / 1000;  % USD/kg battery
C_Labor_hydro       = 307.36 / 1000;                % USD/kg battery
C_Disassemble_hydro = 12.07  / 1000;                % USD/kg battery
C_Equip_hydro       = 52.00  / 1000;                % USD/kg battery
C_Sewage_hydro      = 141.14 / 1000;                % USD/kg battery

Fixed_Op_Cost = C_Electricity_hydro + C_Labor_hydro + ...
                C_Disassemble_hydro + C_Equip_hydro + C_Sewage_hydro;


%% 4) SOH-dependent action-value functions
% 2.1 Construct the baseline reuse value curve from the empirical SOH trajectory

% Identify the endpoint where the empirical SOH trajectory remains above 0.4
valid_end_idx = find(SOH_data >= 0.4);   end_idx = valid_end_idx(end);

% Identify all starting points with SOH between 1.0 and 0.4
start_indices = find(SOH_data <= 1.0 & SOH_data >= 0.4);
num_cases = length(start_indices);
a = zeros(num_cases, 1);   V1 = zeros(num_cases, 1);

for k = 1:num_cases
    start_idx = start_indices(k);

    SOH_slice = SOH_data(start_idx : end_idx);

    a(k) = SOH_slice(1);
    days_elapsed = (0 : length(SOH_slice)-1)';

    SOH_diff = 1 - SOH_slice;
    Poly_term = -0.1532 .* (SOH_diff.^2) + 0.003923 .* SOH_diff + 0.9530;
    Daily_Value_Raw = Q_pack .* SOH_slice .* (Poly_term .* p_high - p_low);

    Discount_Factor = 1 ./ ((1 + r) .^ (days_elapsed / 365));
    V1(k) = sum(Daily_Value_Raw .* Discount_Factor);
end

[a, sort_idx] = sort(a);  V1 = V1(sort_idx);


if max(a) < 1.0
    a = [a; 1.0];
    slope = (V1(end) - V1(end-1)) / (a(end) - a(end-1));
    V1 = [V1; V1(end) + slope * (1.0 - a(end-1))];
end


% 2.2 Define dynamic action-value functions for the three recertification pathways

C_A1_extra = 10;    % extra cost for direct reuse, including transport, testing, integration, and installation
C_A2_extra = 15;    % extra cost for refurbishment, including disassembly, labor, regrouping, and retesting

% Action 3: hydrometallurgical recycling value function based on stoichiometric reactions
Y_Li2CO3_func = @(soh) (PosAcMass / M_LiFePO4) .* (soh ./ 2) .* M_Li2CO3_half .* Rec_Rate_Chem;
Y_H2SO4_func  = @(soh) (PosAcMass / M_LiFePO4) .* (soh ./ 2) .* M_H2SO4;
Y_H2O2_func   = @(soh) (PosAcMass / M_LiFePO4) .* (soh ./ 2) .* M_H2O2;
Y_Na2CO3_func = @(soh) (PosAcMass / M_LiFePO4) .* (soh ./ 2) .* M_Na2CO3;

calc_V_reuse_base = @(soh) interp1(a, V1, soh, 'linear', 'extrap');
calc_V_reuse = @(soh) calc_V_reuse_base(soh) - C_A1_extra;

calc_C_refurbish = @(soh) C0 + C1 .* (1 - soh).^gamma;
calc_V_refurbish_base = @(soh) calc_V_reuse_base(min(soh + beta_refurbish .* (1 - soh), 1.0)) - calc_C_refurbish(soh);
calc_V_refurbish = @(soh) calc_V_refurbish_base(soh) - C_A1_extra - C_A2_extra;

calc_V_recycle = @(soh) M_pack .* Exchange_Rate .* ( ...
    (Y_Li2CO3_func(soh) .* P_Li2CO3 + Base_Y_FePO4 .* P_FePO4 + Base_Y_Graphite .* P_Graphite + Base_Y_Al .* P_Al + Base_Y_Cu .* P_Cu) ...
    - (Y_H2SO4_func(soh) .* P_H2SO4 + Y_H2O2_func(soh) .* P_H2O2 + Y_Na2CO3_func(soh) .* P_Na2CO3) ...
    - (PosAcMass .* C_Degraded + Fixed_Op_Cost) ...
    );


%% 5) Load k-dependent residual-error extrapolation model

error_model_file = cfg.error_model_mat;

if ~exist(error_model_file, 'file')
    error('Part3 residual-error model file not found: %s', error_model_file);
end

ErrorModel = load(error_model_file);

required_error_vars = { ...
    'k_emp', ...
    'k_vals', ...
    'err_cell', ...
    'rmse_target', ...
    'w_curve', ...
    'muM_curve', ...
    'sigM_curve', ...
    'muR_curve', ...
    'sigR_curve', ...
    'region', ...
    'cfg'};

for ii = 1:numel(required_error_vars)
    if ~isfield(ErrorModel, required_error_vars{ii})
        error('Required variable "%s" was not found in %s.', ...
            required_error_vars{ii}, error_model_file);
    end
end

k_emp = ErrorModel.k_emp(:);
k_vals = ErrorModel.k_vals(:);
err_cell = ErrorModel.err_cell;

rmse_target = ErrorModel.rmse_target(:);
w_curve     = ErrorModel.w_curve(:);
muM_curve   = ErrorModel.muM_curve(:);
sigM_curve  = ErrorModel.sigM_curve(:);
muR_curve   = ErrorModel.muR_curve(:);
sigR_curve  = ErrorModel.sigR_curve(:);

region = ErrorModel.region;

if isfield(ErrorModel.cfg, 'k_anchor')
    k_anchor = ErrorModel.cfg.k_anchor;
else
    k_anchor = 21;
end

if isfield(ErrorModel.cfg, 'k_bridge_end')
    k_bridge_end = ErrorModel.cfg.k_bridge_end;
else
    k_bridge_end = 26;
end

if max(k_vals) < 50
    error(['The loaded residual-error model only covers k = %d to %d. ', ...
        'Please rerun P3_Exp03_label_dependent_residual_extrapolation.m with cfg.k_extrap_max = 50.'], ...
        min(k_vals), max(k_vals));
end

if numel(k_vals) ~= numel(rmse_target) || ...
        numel(k_vals) ~= numel(w_curve) || ...
        numel(k_vals) ~= numel(muM_curve) || ...
        numel(k_vals) ~= numel(sigM_curve) || ...
        numel(k_vals) ~= numel(muR_curve) || ...
        numel(k_vals) ~= numel(sigR_curve)
    error('The loaded residual-error model has inconsistent curve lengths.');
end

fprintf('Residual-error model loaded from: %s\n', error_model_file);
fprintf('Loaded k range: %d to %d\n', min(k_vals), max(k_vals));

N_sim = cfg.N_sim;
rng(cfg.random_seed);

% Common random numbers reused across k values.
base_u    = rand(N_sim, 1);
base_z    = randn(N_sim, 1);
base_pick = rand(N_sim, 1);

% Preserve the original SOH Monte Carlo sequence. The independent bridge
% selector uses a separate stream so that adding it does not shift s_true.
s_true = 0.4 + 0.6 * rand(N_sim, 1);
bridge_stream = RandStream('mt19937ar', ...
    'Seed', cfg.random_seed + 1001);
base_bridge = rand(bridge_stream, N_sim, 1);

fprintf('>>> Running dense k-grid search from k = %d to %d...\n', ...
    min(k_vals), max(k_vals));

Pi_True = [calc_V_reuse(s_true), calc_V_refurbish(s_true), calc_V_recycle(s_true)];
[Pi_True_Max, PerfectInfo_Action_i] = max(Pi_True, [], 2);
% Legacy alias retained for compatibility with existing saved workspaces.
True_Action_i = PerfectInfo_Action_i; %#ok<NASGU>

T1_grid = 0.4 : 0.005 : 0.5;
T2_grid = 0.85 : 0.005 : 1;

E_L_base = zeros(length(k_vals), 1);
O_base = zeros(length(k_vals), 1);
H_base = zeros(length(k_vals), 1);
R_base = zeros(length(k_vals), 1);
T1_base = zeros(length(k_vals), 1);
T2_base = zeros(length(k_vals), 1);

% Diagnostics verify that Part4 uses the same empirical/bridge/extrapolated
% residual construction exported by Part3 Exp03.
noise_source_type = strings(length(k_vals), 1);
noise_generated_RMSE = nan(length(k_vals), 1);
noise_target_RMSE = rmse_target;
noise_bridge_alpha = zeros(length(k_vals), 1);
noise_bridge_RMSE_scale = ones(length(k_vals), 1);
noise_parametric_fraction = nan(length(k_vals), 1);

for i = 1:length(k_vals)
    k_current = k_vals(i);

    [sampled_noise, noise_diag] = local_build_noise_by_k( ...
        k_current, ...
        k_emp, k_anchor, k_bridge_end, ...
        err_cell, ...
        w_curve, muM_curve, sigM_curve, muR_curve, sigR_curve, rmse_target, k_vals, ...
        base_u, base_z, base_pick, base_bridge);

    noise_source_type(i) = string(noise_diag.source_type);
    noise_generated_RMSE(i) = noise_diag.generated_RMSE;
    noise_bridge_alpha(i) = noise_diag.bridge_alpha;
    noise_bridge_RMSE_scale(i) = noise_diag.bridge_RMSE_scale;
    noise_parametric_fraction(i) = noise_diag.parametric_fraction_realized;

    s_pred = min(max(s_true + sampled_noise, 0), 1.0);

    min_L = inf;
    for T1 = T1_grid
        for T2 = T2_grid
            if T1 >= T2
                continue;
            end

            Pred_Action_j = 3 * ones(N_sim, 1);
            Pred_Action_j(s_pred >= T1 & s_pred < T2) = 2;
            Pred_Action_j(s_pred >= T2) = 1;

            idx_pred = sub2ind([N_sim, 3], (1:N_sim)', Pred_Action_j);
            O_arr = max(Pi_True_Max - Pi_True(idx_pred), 0);

            is_G1_error = (PerfectInfo_Action_i == 3 & Pred_Action_j == 2) | ...
                (PerfectInfo_Action_i == 2 & Pred_Action_j == 3);
            is_G2_error = (PerfectInfo_Action_i == 1 & Pred_Action_j == 2) | ...
                (PerfectInfo_Action_i == 2 & Pred_Action_j == 1);

            Current_Eta = zeros(N_sim, 1);
            Current_Eta(is_G1_error) = Eta_1;
            Current_Eta(is_G2_error) = Eta_2;

            consequential_mismatch = (Pred_Action_j ~= PerfectInfo_Action_i) & ...
                (O_arr > Current_Eta);
            Excess_Loss = max(0, O_arr - Current_Eta);

            H_arr = consequential_mismatch .* Lambda_H;
            R_arr = (Pred_Action_j < PerfectInfo_Action_i) .* consequential_mismatch .* (Lambda_R .* Excess_Loss);

            E_L = mean(O_arr + H_arr + R_arr);

            if E_L < min_L
                min_L = E_L;
                O_base(i) = mean(O_arr);
                H_base(i) = mean(H_arr);
                R_base(i) = mean(R_arr);
                T1_base(i) = T1;
                T2_base(i) = T2;
            end
        end
    end
    E_L_base(i) = min_L;
end



%% 7) Optimal policy reconstruction at the fixed-scale optimum

Fixed_O = O_base * Fixed_Scale_N;
Fixed_H = H_base * Fixed_Scale_N;
Fixed_R = R_base * Fixed_Scale_N;
Fixed_Model = (k_vals .* c_pack + c_train);
Fixed_Total_Cost = Fixed_O + Fixed_H + Fixed_R + Fixed_Model;
[~, opt_k_idx] = min(Fixed_Total_Cost);
opt_k = k_vals(opt_k_idx);
opt_T1 = T1_base(opt_k_idx);
opt_T2 = T2_base(opt_k_idx);
Scale_Factor = Fixed_Scale_N / N_sim;

fprintf('>>> Extracting sample-level results at the optimal k* = %d...\n', opt_k);

% Reconstruct predicted SOH and assigned actions at the optimal k
noise_opt = local_build_noise_by_k( ...
    opt_k, ...
    k_emp, k_anchor, k_bridge_end, ...
    err_cell, ...
    w_curve, muM_curve, sigM_curve, muR_curve, sigR_curve, rmse_target, k_vals, ...
    base_u, base_z, base_pick, base_bridge);

s_pred_opt = min(max(s_true + noise_opt, 0), 1.0);

Pred_Action_opt = 3 * ones(N_sim, 1);
Pred_Action_opt(s_pred_opt >= opt_T1 & s_pred_opt < opt_T2) = 2;
Pred_Action_opt(s_pred_opt >= opt_T2) = 1;

idx_pred_opt = sub2ind([N_sim, 3], (1:N_sim)', Pred_Action_opt);
O_arr_opt = max(Pi_True_Max - Pi_True(idx_pred_opt), 0);

% Apply opportunity-loss, handling/rework and risk accounting
is_G1_opt = (PerfectInfo_Action_i == 3 & Pred_Action_opt == 2) | (PerfectInfo_Action_i == 2 & Pred_Action_opt == 3);
is_G2_opt = (PerfectInfo_Action_i == 1 & Pred_Action_opt == 2) | (PerfectInfo_Action_i == 2 & Pred_Action_opt == 1);
Eta_opt = zeros(N_sim, 1); Eta_opt(is_G1_opt) = Eta_1; Eta_opt(is_G2_opt) = Eta_2;

consequential_mismatch_opt = (Pred_Action_opt ~= PerfectInfo_Action_i) & ...
    (O_arr_opt > Eta_opt);
Excess_opt = max(0, O_arr_opt - Eta_opt);

H_arr_opt = consequential_mismatch_opt .* Lambda_H;
R_arr_opt = (Pred_Action_opt < PerfectInfo_Action_i) .* consequential_mismatch_opt .* (Lambda_R .* Excess_opt);

Total_Loss_opt = O_arr_opt + H_arr_opt + R_arr_opt;

% The executed pathway value already reflects opportunity loss relative to
% the perfect-information pathway. Therefore opportunity loss is not
% subtracted again when computing net realized value.
Executed_Pathway_Value_opt = Pi_True(idx_pred_opt);
PerfectInfo_Pathway_Value_opt = Pi_True_Max;
Net_Realized_Value_opt = Executed_Pathway_Value_opt - H_arr_opt - R_arr_opt;
Net_Realized_Value_check = PerfectInfo_Pathway_Value_opt ...
    - O_arr_opt - H_arr_opt - R_arr_opt;

accounting_gap = max(abs( ...
    Net_Realized_Value_opt - Net_Realized_Value_check));
assert(accounting_gap < 1e-8, ...
    'Net-value accounting identity failed. Maximum gap = %.3e.', ...
    accounting_gap);

% Legacy alias retained for compatibility with older plotting scripts.
Net_Revenue_opt = Net_Realized_Value_opt;

%% 8) Save the full fixed-scale LFP workspace before figure generation

Noise_Diagnostic_Table = table( ...
    k_vals, ...
    noise_source_type, ...
    noise_target_RMSE, ...
    noise_generated_RMSE, ...
    noise_bridge_alpha, ...
    noise_bridge_RMSE_scale, ...
    noise_parametric_fraction, ...
    'VariableNames', { ...
    'k', ...
    'Residual_source', ...
    'RMSE_target', ...
    'RMSE_generated_in_Part4', ...
    'Bridge_alpha', ...
    'Bridge_RMSE_scale', ...
    'Parametric_fraction_realized'});

save(cfg.workspace_mat, '-v7.3');
fprintf('>>> Full fixed-scale LFP workspace saved to: %s\n', cfg.workspace_mat);


%% 9) Figure 1: fixed-scale cost decomposition
fig_cost_breakdown = figure('Name', sprintf('MainFig02b_fixed_scale_LFP_cost_decomposition_N%d', Fixed_Scale_N), ...
    'Color', 'w', 'Position', [100, 450, 700, 500]);

bar_data = [Fixed_O, Fixed_H, Fixed_R, Fixed_Model] / 1e4;

b = bar(k_vals, bar_data, 'stacked', 'EdgeColor', 'none');
hold on;

% Colors
b(1).FaceColor = [0.93, 0.69, 0.13];   % Opportunity loss
b(2).FaceColor = [0.49, 0.18, 0.56];   % Mismatch handling and rework cost
b(3).FaceColor = [0.85, 0.33, 0.10];   % Risk penalty
b(4).FaceColor = [0.00, 0.45, 0.74];   % SOH labelling and adaptation cost

% Total cost curve
h_total = plot(k_vals, Fixed_Total_Cost/1e4, '-k', ...
    'LineWidth', 2.8, 'DisplayName', 'Total Cost');

% Optimal K*
