%% 12) Figure 4: cost-consistent net-value curves

% 1. Calculate the net value of each action
%    J_action(:, j) denotes the sample-level net value if action j is enforced.

J_action = zeros(N_sim, 3);

for act_j = 1:3

% Baseline economic value of the selected action under the true SOH
    ch_v = Pi_True(:, act_j);

% Opportunity loss relative to the perfect-information reference action
    O_tmp = max(Pi_True_Max - ch_v, 0);

% Identify the misclassification type
    is_G1 = (PerfectInfo_Action_i == 3 & act_j == 2) | ...
            (PerfectInfo_Action_i == 2 & act_j == 3);

    is_G2 = (PerfectInfo_Action_i == 1 & act_j == 2) | ...
            (PerfectInfo_Action_i == 2 & act_j == 1);

    Eta_tmp = zeros(N_sim, 1);
    Eta_tmp(is_G1) = Eta_1;
    Eta_tmp(is_G2) = Eta_2;

% Apply the same handling/rework and risk logic as in the grid-search objective
    consequential_mismatch_tmp = (act_j ~= PerfectInfo_Action_i) & ...
        (O_tmp > Eta_tmp);
    Excess_tmp  = max(0, O_tmp - Eta_tmp);

    H_tmp = consequential_mismatch_tmp .* Lambda_H;
    R_tmp = (act_j < PerfectInfo_Action_i) .* consequential_mismatch_tmp .* (Lambda_R .* Excess_tmp);

% Net value equals executed pathway value minus handling/rework and risk costs.
% This is equivalent to maximizing Pi_True_Max - (O + H + R).
    J_action(:, act_j) = ch_v - H_tmp - R_tmp;
end


% 2. Bin samples by predicted SOH
x_grid = 0.35 : 0.0025 : 1.00;
half_width = 0.005;

J_curve = nan(numel(x_grid), 3);
N_bin   = zeros(numel(x_grid), 1);

for ii = 1:numel(x_grid)

    x0 = x_grid(ii);

    idx_bin = (s_pred_opt >= x0 - half_width) & ...
              (s_pred_opt <  x0 + half_width);

    N_bin(ii) = sum(idx_bin);

    if N_bin(ii) >= 30
        J_curve(ii, 1) = mean(J_action(idx_bin, 1), 'omitnan');
        J_curve(ii, 2) = mean(J_action(idx_bin, 2), 'omitnan');
        J_curve(ii, 3) = mean(J_action(idx_bin, 3), 'omitnan');
    end
end


% 3. Apply mild smoothing
J_plot_1 = smoothdata(J_curve(:,1), 'movmean', 3, 'omitnan');
J_plot_2 = smoothdata(J_curve(:,2), 'movmean', 3, 'omitnan');
J_plot_3 = smoothdata(J_curve(:,3), 'movmean', 3, 'omitnan');

J_env = max([J_plot_1, J_plot_2, J_plot_3], [], 2, 'omitnan');


% 4. Check the distance between curve intersections and grid-search thresholds
D32 = J_plot_2 - J_plot_3;   % A2 - A3, corresponding to T1
D12 = J_plot_1 - J_plot_2;   % A1 - A2, corresponding to T2

idx_near_T1 = find(x_grid >= opt_T1 - 0.05 & x_grid <= opt_T1 + 0.05);
idx_cross_T1 = [];

if ~isempty(idx_near_T1)
    tmp = idx_near_T1(1:end-1);
    cross_candidate = tmp(D32(tmp) .* D32(tmp+1) <= 0);
    if ~isempty(cross_candidate)
        [~, id_min] = min(abs(x_grid(cross_candidate) - opt_T1));
        idx_cross_T1 = cross_candidate(id_min);
    end
end

if isempty(idx_cross_T1)
    T1_curve_cross = NaN;
else
    i0 = idx_cross_T1;
    T1_curve_cross = x_grid(i0) - D32(i0) * ...
        (x_grid(i0+1) - x_grid(i0)) / (D32(i0+1) - D32(i0));
end

idx_near_T2 = find(x_grid >= opt_T2 - 0.05 & x_grid <= opt_T2 + 0.05);
idx_cross_T2 = [];

if ~isempty(idx_near_T2)
    tmp = idx_near_T2(1:end-1);
    cross_candidate = tmp(D12(tmp) .* D12(tmp+1) <= 0);
    if ~isempty(cross_candidate)
        [~, id_min] = min(abs(x_grid(cross_candidate) - opt_T2));
        idx_cross_T2 = cross_candidate(id_min);
    end
end

if isempty(idx_cross_T2)
    T2_curve_cross = NaN;
else
    i0 = idx_cross_T2;
    T2_curve_cross = x_grid(i0) - D12(i0) * ...
        (x_grid(i0+1) - x_grid(i0)) / (D12(i0+1) - D12(i0));
end

fprintf('\n========== Fig. 4 threshold-consistency check ==========\n');
fprintf('Grid-search opt_T1 = %.4f\n', opt_T1);
fprintf('Curve intersection T1_curve_cross = %.4f\n', T1_curve_cross);
fprintf('Grid-search opt_T2 = %.4f\n', opt_T2);
fprintf('Curve intersection T2_curve_cross = %.4f\n', T2_curve_cross);
