        b.CData(i, :) = [0.15, 0.15, 0.15];
    elseif vals_full(i) >= 0
        b.CData(i, :) = [0.16, 0.47, 0.78];
    else
        b.CData(i, :) = [0.85, 0.33, 0.10];
    end
end

xline(0, 'k-', 'LineWidth', 1.0);

set(gca, 'YTick', 1:numel(labels), ...
         'YTickLabel', labels, ...
         'YDir', 'reverse', ...
         'FontSize', 11, ...
         'FontName', 'Arial');

xlabel('Value / Cost (USD per pack)');
title(sprintf('A_3 Recycling Pathway Breakdown at Representative SOH = %.3f', mean_soh_rec));

grid on;
box on;

% 6. Value labels
xmax = max(vals_full);
xmin = min(vals_full);
xr = xmax - xmin;
if xr < 1e-6
    xr = 1;
end

for i = 1:numel(vals_full)
    v = vals_full(i);
    if v >= 0
        text(v + 0.02*xr, i, sprintf('%.1f', v), ...
            'HorizontalAlignment', 'left', ...
            'VerticalAlignment', 'middle', ...
            'FontSize', 10, 'FontName', 'Arial');
    else
        text(v - 0.02*xr, i, sprintf('%.1f', v), ...
            'HorizontalAlignment', 'right', ...
            'VerticalAlignment', 'middle', ...
            'FontSize', 10, 'FontName', 'Arial');
    end
end

xlim([xmin - 0.12*xr, xmax + 0.18*xr]);
hold off;

local_save_figure(fig_A3_breakdown, cfg.fig_A3_breakdown, cfg.png_A3_breakdown, cfg.png_resolution);


